import mujoco, numpy as np, time
base=open('model_ref.xml').read()
def build(opt):
    return base.replace('  <size memory=\"2M\"/>\n', '  <size memory=\"2M\"/>\n'+opt)
def timeit(xml, runs=12):
    m=mujoco.MjModel.from_xml_string(xml); ts=[]
    for r in range(runs):
        d=mujoco.MjData(m); rng=np.random.default_rng(1000+r)
        d.qpos+=rng.normal(0,0.01,size=d.qpos.shape); mujoco.mj_forward(m,d)
        n=int(2.0/m.opt.timestep); t0=time.perf_counter()
        for _ in range(n): mujoco.mj_step(m,d)
        ts.append(time.perf_counter()-t0)
    return np.median(ts)
def final(xml,seed):
    m=mujoco.MjModel.from_xml_string(xml); d=mujoco.MjData(m)
    rng=np.random.default_rng(seed); d.qpos+=rng.normal(0,0.01,size=d.qpos.shape); mujoco.mj_forward(m,d)
    for _ in range(int(2.0/m.opt.timestep)): mujoco.mj_step(m,d)
    fp=mujoco.mjtState.mjSTATE_FULLPHYSICS; s=np.zeros(mujoco.mj_stateSize(m,fp)); mujoco.mj_getState(m,d,s,fp); return s
tr=timeit(base)
refs={s:final(base,s) for s in [1,2,3,7,42]}
for name,opt in [
 ('pgs','  <option solver=\"PGS\"/>\n'),
 ('cg','  <option solver=\"CG\"/>\n'),
 ('ls5','  <option ls_iterations=\"5\"/>\n'),
 ('ls1','  <option ls_iterations=\"1\"/>\n'),
 ('cg+contact','  <option solver=\"CG\"><flag contact=\"disable\"/></option>\n'),
 ('pgs+contact','  <option solver=\"PGS\"><flag contact=\"disable\"/></option>\n'),
]:
    try:
        xml=build(opt); t=timeit(xml)
        md=max(np.linalg.norm(final(xml,s)-refs[s]) for s in refs)
        print(f'{name:14s} pctg {t/tr:.3f}  maxdiff {md:.2e}')
    except Exception as e: print(name,'ERR',str(e)[:80])
" 2>&1 | grep -v WARNING

