import mujoco, numpy as np, time
base=open('model_ref.xml').read()
def build(opt): return base.replace('  <size memory=\"2M\"/>\n', '  <size memory=\"2M\"/>\n'+opt)
def run_once(m):
    d=mujoco.MjData(m); rng=np.random.default_rng(np.random.randint(0,10000))
    d.qpos+=rng.normal(0,0.01,size=d.qpos.shape); mujoco.mj_forward(m,d)
    n=int(2.0/m.opt.timestep); t0=time.perf_counter()
    for _ in range(n): mujoco.mj_step(m,d)
    return time.perf_counter()-t0
def final(m,seed):
    d=mujoco.MjData(m); rng=np.random.default_rng(seed); d.qpos+=rng.normal(0,0.01,size=d.qpos.shape); mujoco.mj_forward(m,d)
    for _ in range(int(2.0/m.opt.timestep)): mujoco.mj_step(m,d)
    fp=mujoco.mjtState.mjSTATE_FULLPHYSICS; s=np.zeros(mujoco.mj_stateSize(m,fp)); mujoco.mj_getState(m,d,s,fp); return s
mr=mujoco.MjModel.from_xml_string(base)
seeds=list(np.random.default_rng(0).integers(0,10000,40))
refs={s:final(mr,s) for s in seeds}
variants={
 'pgs':'  <option solver=\"PGS\" tolerance=\"1e-10\"><flag contact=\"disable\"/></option>\n',
 'pgs+act':'  <option solver=\"PGS\" tolerance=\"1e-10\"><flag contact=\"disable\" actuation=\"disable\"/></option>\n',
 'pgs+act+eul':'  <option solver=\"PGS\" tolerance=\"1e-10\" jacobian=\"sparse\"><flag contact=\"disable\" actuation=\"disable\"/></option>\n',
}
models={k:mujoco.MjModel.from_xml_string(build(v)) for k,v in variants.items()}
# warmup
for _ in range(3):
    run_once(mr)
    for m in models.values(): run_once(m)
for k,m in models.items():
    md=max(np.linalg.norm(final(m,s)-refs[s]) for s in seeds)
    ratios=[]
    for trial in range(4):
        tm=np.array([run_once(m) for _ in range(20)]); trf=np.array([run_once(mr) for _ in range(20)])
        ratios.append((tm/trf).mean())
    print(f'{k:14s} maxdiff {md:.2e} pctg(elemmean) {np.mean(ratios):.3f} +-{np.std(ratios):.3f}')
" 2>&1 | grep -v WARNING

